package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
)

type job struct {
	remaining int
}

func main() {
	in := bufio.NewScanner(os.Stdin)
	in.Buffer(make([]byte, 0, 1024), 1024*1024)

	if !in.Scan() {
		return
	}
	header := strings.Fields(in.Text())
	if len(header) < 3 {
		fmt.Println("completed=0 rejected=0 running=0 queued=0")
		return
	}

	workers, _ := strconv.Atoi(header[0])
	queueCap, _ := strconv.Atoi(header[1])
	events, _ := strconv.Atoi(header[2])

	running := make([]job, 0, workers)
	queue := make([]job, 0, queueCap)
	completed := 0
	rejected := 0
	closed := false

	for i := 0; i < events && in.Scan(); i++ {
		parts := strings.Fields(in.Text())
		if len(parts) == 0 {
			continue
		}

		switch parts[0] {
		case "submit":
			if closed || len(parts) < 2 {
				continue
			}
			duration, _ := strconv.Atoi(parts[1])
			j := job{remaining: duration}
			if len(running) < workers {
				running = append(running, j)
			} else if len(queue) < queueCap {
				queue = append(queue, j)
			} else {
				rejected++
			}
		case "tick":
			nextRunning := make([]job, 0, workers)
			for _, current := range running {
				current.remaining--
				if current.remaining <= 0 {
					completed++
					continue
				}
				nextRunning = append(nextRunning, current)
			}
			running = nextRunning
			for len(running) < workers && len(queue) > 0 {
				running = append(running, queue[0])
				queue = queue[1:]
			}
		case "close":
			closed = true
		}
	}

	fmt.Printf("completed=%d rejected=%d running=%d queued=%d\n", completed, rejected, len(running), len(queue))
}

